{
  "grammar": [
    {
      "pattern": "不如 + option A + (來得) + adjective",
      "structure": ["不如", "option A", "來得", "adjective"],
      "explanation_en": "Used to compare two options and express that option A is not as good as the implied alternative. It often implies a suggestion to choose the other option.",
      "title": "不如...來得... (Not as...as)",
      "meaning": "Expresses that one option is inferior to another.",
      "when_to_use": ["When comparing two choices and suggesting the other is better", "When politely pointing out a disadvantage"],
      "when_not_to_use": ["When stating a fact without comparison", "When the comparison is about equality"],
      "pragmatic_notes": "In Taiwan, this pattern is common in polite suggestions, especially when discussing plans or choices with friends or colleagues. It softens the criticism.",
      "word_order_notes": "The structure is '不如 + option A + 來得 + adjective'. The adjective is usually a positive one (e.g., 好, 方便, 快).",
      "english_contrast": "English uses 'not as...as' or '不如' is similar to 'might as well' in suggestions.",
      "korean_contrast": "Similar to 'A보다 B가 더 낫다' (B is better than A).",
      "negative_examples": [
        {
          "text": "不如這家餐廳來得不好。",
          "error": "The adjective after 來得 should be positive (e.g., 好, 方便), not negative."
        }
      ],
      "incorrect_examples": [
        {
          "text": "不如這家餐廳來得不好。",
          "error": "The adjective after 來得 should be positive (e.g., 好, 方便), not negative."
        }
      ],
      "transformation_drills": ["Change '這家餐廳比較好' to '不如那家餐廳來得好'."],
      "production_drills": ["Compare two restaurants using 不如...來得..."],
      "common_error_patterns": ["Using a negative adjective after 來得"],
      "repair_feedback": {
        "word_order": "Place 不如 before the option being compared.",
        "politeness": "This pattern is polite for suggestions.",
        "vocabulary": "Use positive adjectives like 好, 方便, 快."
      }
    },
    {
      "pattern": "要不然 + option A, 要不然 + option B",
      "structure": ["要不然", "option A", "要不然", "option B"],
      "explanation_en": "Presents two alternative options, often as suggestions or choices. It's similar to 'either...or...' but more conversational.",
      "title": "要不然...要不然... (Either...or...)",
      "meaning": "Presents two alternatives.",
      "when_to_use": ["When offering two possible choices", "When suggesting alternatives in a discussion"],
      "when_not_to_use": ["When there are more than two clear options", "When the options are not mutually exclusive"],
      "pragmatic_notes": "Common in casual conversation in Taiwan. It can also imply a consequence if the first option is not taken.",
      "word_order_notes": "Each 要不然 is followed by a full clause (subject + verb + object).",
      "english_contrast": "Similar to 'either...or...' or 'otherwise...'.",
      "korean_contrast": "Similar to '아니면 A, 아니면 B'.",
      "negative_examples": [
        {
          "text": "要不然餐廳，要不然咖啡店。",
          "error": "Each 要不然 should be followed by a full clause, not just a noun."
        }
      ],
      "incorrect_examples": [
        {
          "text": "要不然餐廳，要不然咖啡店。",
          "error": "Each 要不然 should be followed by a full clause, not just a noun."
        }
      ],
      "transformation_drills": ["Change '我們可以去餐廳或咖啡店' to '要不然我們去餐廳，要不然我們去咖啡店'."],
      "production_drills": ["Suggest two options for dinner using 要不然...要不然..."],
      "common_error_patterns": ["Using nouns instead of full clauses after 要不然"],
      "repair_feedback": {
        "word_order": "Place 要不然 at the beginning of each clause.",
        "politeness": "Neutral, can be used in both casual and semi-formal contexts.",
        "vocabulary": "Use complete clauses after each 要不然."
      }
    },
    {
      "pattern": "就 + 這樣 + 決定 / 辦",
      "structure": ["就", "這樣", "決定/辦"],
      "explanation_en": "Used to finalize a decision or plan. It means 'let's go with this' or 'that's settled'.",
      "title": "就這樣決定 (That's settled)",
      "meaning": "Finalizes a decision.",
      "when_to_use": ["When concluding a discussion or negotiation", "When agreeing on a plan"],
      "when_not_to_use": ["When the decision is not yet final", "When you want to leave room for change"],
      "pragmatic_notes": "Very common in Taiwan to end a discussion. It shows agreement and closure. Can be used in both formal and informal settings.",
      "word_order_notes": "The structure is '就 + 這樣 + verb'. The verb is often 決定 or 辦.",
      "english_contrast": "Similar to 'that's settled' or 'let's go with that'.",
      "korean_contrast": "Similar to '그럼 이걸로 결정이다'.",
      "negative_examples": [
        {
          "text": "就這樣決定去餐廳。",
          "error": "The verb after 就這樣 should be 決定 or 辦, not a full clause."
        }
      ],
      "incorrect_examples": [
        {
          "text": "就這樣決定去餐廳。",
          "error": "The verb after 就這樣 should be 決定 or 辦, not a full clause."
        }
      ],
      "transformation_drills": ["Change '我們決定去這家餐廳' to '就這樣決定'."],
      "production_drills": ["Finalize a plan with a friend using 就這樣決定."],
      "common_error_patterns": ["Adding extra information after 決定"],
      "repair_feedback": {
        "word_order": "Place 就 before 這樣.",
        "politeness": "Neutral, but can be softened with 好 or 可以.",
        "vocabulary": "Use 決定 or 辦 after 就這樣."
      }
    }
  ]
}
